const rows = $input.first().json.rows;
const element = rows && rows[0] && rows[0].elements && rows[0].elements[0];

if (!element || element.status !== 'OK') {
  return [{ json: {
    distance_miles: 0,
    distance_text: 'N/A',
    payment: 0,
    rate_per_mile: '0',
    details: 'Distance unavailable'
  }}];
}

const distanceMiles = Math.round(element.distance.value / 1609.34);
const rateStr = $('Edit Fields1').first().json.output.Rate || '0';
const payment = parseFloat(rateStr.replace(/[\$,]/g, ''));
const ratePerMile = distanceMiles > 0 ? (payment / distanceMiles).toFixed(2) : '0';

const pickup = $('Edit Fields1').first().json.output['Pickup Address'] || '';
const dropoff = $('Edit Fields1').first().json.output['Drop-off Address'] || '';

function cityStateZip(addr) {
  const match = addr.match(/([^,]+),\s*([A-Z]{2})\s*(\d{5})/i);
  if (match) return `${match[1].trim()}, ${match[2].toUpperCase()} ${match[3]}`;
  const parts = addr.split(',');
  return parts.length >= 2 ? parts.slice(-2).join(',').trim() : addr;
}

return [{ json: {
  distance_miles: distanceMiles,
  distance_text: element.distance.text,
  payment: payment,
  rate_per_mile: ratePerMile,
  details: `${cityStateZip(pickup)} - ${cityStateZip(dropoff)}`
}}];

const staticData = $getWorkflowStaticData('global');
const jobId = $input.first().json.id;
const key = `llamaparse_retry_${jobId}`;
staticData[key] = (staticData[key] || 0) + 1;
const count = staticData[key];
const exceeded = count > 10;
if (exceeded) { delete staticData[key]; }
return [{ json: { ...$input.first().json, retryCount: count, retryExceeded: exceeded } }];

